body.script:
            document.addEventListener('DOMContentLoaded', () => {

            const container = document.getElementById('chart-container');
            const modal = document.getElementById('infoModal');
            const closeModal = document.getElementById('closeModal');
            const tickerInput = document.getElementById('tickerInput');
            const quickTagsContainer = document.getElementById('quick-tags');
            const bloggerListContainer = document.getElementById('blogger-list');
            const selectAllCheckbox = document.getElementById('selectAllBloggers');

            let dailyOpinions = {};
            let validTradingDays = [];
            let allBloggers = [];
            let selectedBloggers = [];

            const coreAssets = ['SPY', 'QQQ', 'AAPL', 'MSFT', 'GOOGL', 'AMZN', 'NVDA', 'META', 'TSLA', 'BRK'];

            coreAssets.forEach(symbol => {
            const span = document.createElement('span');
            span.className = 'tag-btn';
            span.innerText = symbol;
            span.dataset.symbol = symbol;

            span.addEventListener('click', () => {
            tickerInput.value = symbol;
            updateActiveTag(symbol);
            loadData();
            });
            quickTagsContainer.appendChild(span);
            });

            function updateActiveTag(currentSymbol) {
            document.querySelectorAll('.tag-btn').forEach(tag => {
            tag.classList.toggle('active', tag.dataset.symbol === currentSymbol);
            });
            }

            async function loadBloggers(ticker) {
            try {
            const bRes = await fetch(`/api/charts/bloggers?ticker=${ticker}`);
            const bJson = await bRes.json();
            if (bJson.code === 0 && Array.isArray(bJson.data)) {
            allBloggers = bJson.data;
            selectedBloggers = [...allBloggers];
            renderBloggerList();
            }
            } catch (err) { console.error("[RsAlpha] 加载博主异常:", err); }
            }

            function renderBloggerList() {
            if (allBloggers.length === 0) {
            bloggerListContainer.innerHTML = '
暂无数据';
            return;
            }
            bloggerListContainer.innerHTML = '';
            allBloggers.forEach(blogger => {
            const div = document.createElement('div');
            const isSelected = selectedBloggers.includes(blogger);
            div.className = 'blogger-item' + (isSelected ? ' selected' : '');

            div.innerHTML = `
            ${blogger}
            ✔
            `;

            div.addEventListener('click', () => {
            if (selectedBloggers.includes(blogger)) {
            selectedBloggers = selectedBloggers.filter(b => b !== blogger);
            } else {
            selectedBloggers.push(blogger);
            }
            updateSelectAllState();
            renderBloggerList();
            loadDataWithSelectedBloggers();
            });
            bloggerListContainer.appendChild(div);
            });
            }

            function updateSelectAllState() {
            selectAllCheckbox.checked = selectedBloggers.length === allBloggers.length;
            }

            selectAllCheckbox.addEventListener('change', (e) => {
            selectedBloggers = e.target.checked ? [...allBloggers] : [];
            renderBloggerList();
            loadDataWithSelectedBloggers();
            });

            async function loadDataWithSelectedBloggers() {
            const ticker = tickerInput.value.toUpperCase().trim();
            if (!ticker) return;

            dailyOpinions = {};
            validTradingDays = [];

            try {
            const kRes = await fetch(`/api/charts/kline?symbol=${ticker}`);
            const kJson = await kRes.json();
            if (kJson.code === 0 && Array.isArray(kJson.data)) {
            candleSeries.setData(kJson.data);
            validTradingDays = kJson.data.map(item => typeof item.time === 'object' ? `${item.time.year}-${String(item.time.month).padStart(2, '0')}-${String(item.time.day).padStart(2, '0')}` : item.time);
            }

            let markersUrl = `/api/charts/markers?ticker=${ticker}`;
            if (selectedBloggers.length > 0 && selectedBloggers.length < allBloggers.length) {
            markersUrl += '&bloggers=' + selectedBloggers.join('&bloggers=');
            }

            const mRes = await fetch(markersUrl);
            const mJson = await mRes.json();

            if (mJson.code === 0 && Array.isArray(mJson.data)) {
            mJson.data.forEach(item => {
            const rawTimestamp = item.timestamp || '';
            const rawDateStr = rawTimestamp.substring(0, 10);
            const alignDateStr = getClosestTradingDay(rawDateStr);

            let sentiment = 1;
            if (item.sentiment_score !== undefined) sentiment = item.sentiment_score;
            else if (item.content) {
            const str = item.content.toLowerCase();
            if (str.includes('跌') || str.includes('空') || str.includes('风险')) sentiment = -1;
            else if (str.includes('中性') || str.includes('观望')) sentiment = 0;
            }

            const newOpinion = {
            user: (item.user || item.blogger || '分析师').trim(),
            horizon: (item.horizon || '未定周期').trim(),
            content: (item.content || item.strategy || '').trim(),
            sentiment: sentiment,
            originalDate: rawDateStr,
            time: rawTimestamp.split(' ')[1] || '',
            fingerprint: md5(`${item.user}|${item.content}`)
            };

            if (!dailyOpinions[alignDateStr]) dailyOpinions[alignDateStr] = [];
            if (!dailyOpinions[alignDateStr].some(e => e.fingerprint === newOpinion.fingerprint)) {
            dailyOpinions[alignDateStr].push(newOpinion);
            }
            });

            // 💡 构建副图指标：计算每日共振强度和情绪倾向
            const resonanceData = [];
            Object.keys(dailyOpinions).forEach(date => {
            const opinions = dailyOpinions[date];
            let sentimentScore = 0;
            opinions.forEach(op => sentimentScore += op.sentiment);

            // 根据综合得分决定柱子颜色
            let barColor = 'rgba(203, 213, 225, 0.6)'; // 中性偏灰
            if (sentimentScore > 0) barColor = 'rgba(246, 70, 93, 0.7)'; // 偏多 (红)
            else if (sentimentScore < 0) barColor = 'rgba(14, 203, 129, 0.7)'; // 偏空 (绿)

            resonanceData.push({
            time: date,
            value: opinions.length, // 高度代表发声总数
            color: barColor
            });
            });

            resonanceData.sort((a, b) => new Date(a.time).getTime() - new Date(b.time).getTime());
            volumeSeries.setData(resonanceData);
            }
            } catch (err) { console.error("[RsAlpha] 加载异常:", err); }
            }

            // 💡 图表配置：更干净的背景、网格线和莫兰迪色K线
            const chart = LightweightCharts.createChart(container, {
            layout: { background: { type: 'solid', color: '#ffffff' }, textColor: '#64748b' },
            grid: { vertLines: { color: '#f8fafc' }, horzLines: { color: '#f8fafc' } },
            timeScale: { borderColor: '#f1f5f9', timeVisible: true },
            crosshair: { mode: LightweightCharts.CrosshairMode.Normal }
            });

            const candleSeries = chart.addCandlestickSeries({
            upColor: '#F6465D', downColor: '#0ECB81', borderVisible: false,
            wickUpColor: '#F6465D', wickDownColor: '#0ECB81',
            });

            // 💡 新增副图：共振强度柱状图 (放置在底部 20% 区域)
            const volumeSeries = chart.addHistogramSeries({
            priceFormat: { type: 'volume' },
            priceScaleId: '', // 无需独立刻度，叠加显示
            scaleMargins: { top: 0.8, bottom: 0 },
            });

            new ResizeObserver(entries => {
            if (!entries.length) return;
            const rect = entries[0].contentRect;
            chart.applyOptions({ height: rect.height, width: rect.width });
            }).observe(container);

            closeModal.onclick = () => modal.style.display = "none";
            window.onclick = (e) => { if (e.target === modal) modal.style.display = "none"; }

            function getClosestTradingDay(targetDateStr) {
            if (!validTradingDays.length || validTradingDays.includes(targetDateStr)) return targetDateStr;
            for (let i = validTradingDays.length - 1; i >= 0; i--) {
            if (validTradingDays[i] <= targetDateStr) return validTradingDays[i];
            }
            return targetDateStr;
            }

            async function loadData() {
            const ticker = tickerInput.value.toUpperCase().trim();
            if (!ticker) return;
            updateActiveTag(ticker);
            await loadBloggers(ticker);
            await loadDataWithSelectedBloggers();
            }

            chart.subscribeClick((param) => {
            if (!param || !param.time) return;
            let clickedDate = param.time;
            if (typeof param.time === 'object') {
            clickedDate = `${param.time.year}-${String(param.time.month).padStart(2, '0')}-${String(param.time.day).padStart(2, '0')}`;
            } else if (typeof param.time === 'string') {
            clickedDate = param.time.substring(0, 10);
            }

            if (dailyOpinions[clickedDate] && dailyOpinions[clickedDate].length > 0) {
            const opinions = dailyOpinions[clickedDate];
            const bloggerGroups = {};
            opinions.forEach(op => {
            if (!bloggerGroups[op.user]) bloggerGroups[op.user] = [];
            bloggerGroups[op.user].push(op);
            });

            const groupedArray = Object.keys(bloggerGroups).map(blogger => {
            const posts = bloggerGroups[blogger];
            let aggSent = 1;
            if (posts.some(p => p.sentiment === -1)) aggSent = -1;
            else if (posts.some(p => p.sentiment === 0)) aggSent = 0;
            return { blogger, sentiment: aggSent, posts };
            });
            groupedArray.sort((a, b) => b.sentiment - a.sentiment);

            document.getElementById('modalTitle').innerHTML =
            `${clickedDate} 投研复盘 汇聚 ${groupedArray.length} 位大V · 共 ${opinions.length} 条策略`;

            let htmlStr = '';
            groupedArray.forEach(group => {
            let borderClass = 'border-neutral';
            let sentimentTitle = '🟡 偏中性';
            if (group.sentiment === 1) { borderClass = 'border-bull'; sentimentTitle = '🔴 偏乐观'; }
            else if (group.sentiment === -1) { borderClass = 'border-bear'; sentimentTitle = '🟢 提示防守'; }

            htmlStr += `




                    🎯 ${group.blogger} (${group.posts.length} 策略)
                    ${sentimentTitle}
                `;

                group.posts.forEach((op, index) => {
                let badgeHtml = '🟡 观望';
                if (op.sentiment === 1) badgeHtml = '🔴 看多';
                else if (op.sentiment === -1) badgeHtml = '🟢 看空/减仓';

                htmlStr += `




                        🕒 ${op.originalDate !== clickedDate ? op.originalDate.substring(5) + ' ' : ''}${op.time}
                        ⏱ ${op.horizon}
                        ${badgeHtml}


${op.content}
                `;
                if (index < group.posts.length - 1) htmlStr += ``;
                });
                htmlStr += ``;
            });
            document.getElementById('modalBody').innerHTML = htmlStr;
            modal.style.display = "flex";
            }
            });

            document.getElementById('loadBtn').addEventListener('click', loadData);
            document.getElementById('tickerInput').addEventListener('keypress', (e) => { if (e.key === 'Enter') loadData(); });

            tickerInput.value = 'SPY';
            loadData();
            });
